1	import { useEffect, useState } from 'react';
2	import { DataGrid } from '@/shared/components/DataGrid/DataGrid';
3	import { SearchForm } from '@/shared/components/SearchForm/SearchForm';
4	import { Input } from '@/shared/components/ui/input';
5	import { DomainDetailDialog } from './DomainDetailDialog';
6	import { getDomainById, searchDomains } from './domainApi';
7	
8	const dataTypeOptions = ['', 'VARCHAR', 'CHAR', 'NUMERIC', 'DATETIME'];
9	
10	const columns = [
11	    { key: 'stdDmnNm', header: '도메인명', sortable: true, width: 220 },
12	    { key: 'stdDmnGroupNm', header: '그룹명', sortable: true, width: 140 },
13	    { key: 'stdDmnClsfNm', header: '분류명', sortable: true, width: 140 },
14	    { key: 'dataTypeNm', header: '데이터타입', sortable: true, width: 110 },
15	    { key: 'dataLen', header: '길이', sortable: false, width: 80, align: 'end' },
16	    { key: 'unitNm', header: '단위', sortable: false, width: 80 },
17	    { key: 'enctCycl', header: '제정차수', sortable: false, width: 140 },
18	    { key: 'useYn', header: '사용', sortable: false, width: 70, align: 'center' },
19	];
20	
21	const initialFilters = {
22	    stdDmnNm: '',
23	    stdDmnGroupNm: '',
24	    stdDmnClsfNm: '',
25	    dataTypeNm: '',
26	    useYn: '',
27	};
28	
29	const emptyToNull = (value) => {
30	    const next = `${value ?? ''}`.trim();
31	    return next.length ? next : null;
32	};
33	
34	const toSnakeCase = (value) => {
35	    return value.replace(/[A-Z]/g, (match) => `_${match.toLowerCase()}`);
36	};
37	
38	export const DomainListPage = () => {
39	    const [filters, setFilters] = useState(initialFilters);
40	    const [request, setRequest] = useState({ page: 1, size: 20 });
41	    const [selectedId, setSelectedId] = useState(null);
42	    const [pageData, setPageData] = useState(null);
43	    const [selectedDomain, setSelectedDomain] = useState(null);
44	
45	    useEffect(() => {
46	        let active = true;
47	
48	        searchDomains(request).then((response) => {
49	            if (active) {
50	                setPageData(response);
51	            }
52	        });
53	
54	        return () => {
55	            active = false;
56	        };
57	    }, [request]);
58	
59	    useEffect(() => {
60	        if (selectedId === null || selectedId === undefined) {
61	            return undefined;
62	        }
63	
64	        let active = true;
65	
66	        getDomainById(selectedId).then((response) => {
67	            if (active) {
68	                setSelectedDomain(response);
69	            }
70	        });
71	
72	        return () => {
73	            active = false;
74	        };
75	    }, [selectedId]);
76	
77	    return (
78	        <div className='space-y-6'>
79	            <SearchForm
80	                onSubmit={() => {
81	                    setRequest({
82	                        page: 1,
83	                        size: request.size,
84	                        stdDmnNm: emptyToNull(filters.stdDmnNm),
85	                        stdDmnGroupNm: emptyToNull(filters.stdDmnGroupNm),
86	                        stdDmnClsfNm: emptyToNull(filters.stdDmnClsfNm),
87	                        dataTypeNm: emptyToNull(filters.dataTypeNm),
88	                        useYn: emptyToNull(filters.useYn),
89	                    });
90	                }}
91	                onReset={() => {
92	                    setFilters(initialFilters);
93	                    setRequest({ page: 1, size: request.size });
94	                }}
95	            >
96	                <div className='grid w-full gap-3 md:grid-cols-2 xl:grid-cols-5'>
97	                    <div className='space-y-2'>
98	                        <label className='text-sm font-medium text-foreground' htmlFor='stdDmnNm'>
99	                            도메인명
100	                        </label>
101	                        <Input
102	                            id='stdDmnNm'
103	                            value={filters.stdDmnNm}
104	                            onChange={(event) => setFilters((current) => ({ ...current, stdDmnNm: event.target.value }))}
105	                        />
106	                    </div>
107	                    <div className='space-y-2'>
108	                        <label className='text-sm font-medium text-foreground' htmlFor='stdDmnGroupNm'>
109	                            그룹명
110	                        </label>
111	                        <Input
112	                            id='stdDmnGroupNm'
113	                            value={filters.stdDmnGroupNm}
114	                            onChange={(event) =>
115	                                setFilters((current) => ({ ...current, stdDmnGroupNm: event.target.value }))
116	                            }
117	                        />
118	                    </div>
119	                    <div className='space-y-2'>
120	                        <label className='text-sm font-medium text-foreground' htmlFor='stdDmnClsfNm'>
121	                            분류명
122	                        </label>
123	                        <Input
124	                            id='stdDmnClsfNm'
125	                            value={filters.stdDmnClsfNm}
126	                            onChange={(event) =>
127	                                setFilters((current) => ({ ...current, stdDmnClsfNm: event.target.value }))
128	                            }
129	                        />
130	                    </div>
131	                    <div className='space-y-2'>
132	                        <label className='text-sm font-medium text-foreground' htmlFor='dataTypeNm'>
133	                            데이터타입
134	                        </label>
135	                        <select
136	                            id='dataTypeNm'
137	                            className='flex h-10 w-full rounded-md border border-input bg-background px-3 py-2 text-sm text-foreground'
138	                            value={filters.dataTypeNm}
139	                            onChange={(event) => setFilters((current) => ({ ...current, dataTypeNm: event.target.value }))}
140	                        >
141	                            {dataTypeOptions.map((option) => (
142	                                <option key={option || 'all'} value={option}>
143	                                    {option || '전체'}
144	                                </option>
145	                            ))}
146	                        </select>
147	                    </div>
148	                    <div className='space-y-2'>
149	                        <label className='text-sm font-medium text-foreground' htmlFor='useYn'>
150	                            사용여부
151	                        </label>
152	                        <select
153	                            id='useYn'
154	                            className='flex h-10 w-full rounded-md border border-input bg-background px-3 py-2 text-sm text-foreground'
155	                            value={filters.useYn}
156	                            onChange={(event) => setFilters((current) => ({ ...current, useYn: event.target.value }))}
157	                        >
158	                            <option value=''>전체</option>
159	                            <option value='Y'>사용</option>
160	                            <option value='N'>미사용</option>
161	                        </select>
162	                    </div>
163	                </div>
164	            </SearchForm>
165	
166	            <DataGrid
167	                columns={columns}
168	                pageData={pageData}
169	                pageSizeOptions={[10, 20, 50, 100]}
170	                onPageChange={({ page, size }) => setRequest((current) => ({ ...current, page, size }))}
171	                onSortChange={({ active, direction }) =>
172	                    setRequest((current) => ({
173	                        ...current,
174	                        page: 1,
175	                        sortBy: direction ? toSnakeCase(active) : null,
176	                        sortDir: direction || null,
177	                    }))
178	                }
179	                onRowClick={(row) => {
180	                    setSelectedDomain(null);
181	                    setSelectedId(row.id);
182	                }}
183	            />
184	
185	            <DomainDetailDialog
186	                domain={selectedDomain}
187	                open={Boolean(selectedDomain)}
188	                onOpenChange={(open) => {
189	                    if (!open) {
190	                        setSelectedId(null);
191	                        setSelectedDomain(null);
192	                    }
193	                }}
194	            />
195	        </div>
196	    );
197	};
