10	
11	export const LoginPage = () => {
12	    const navigate = useNavigate();
13	    const [searchParams] = useSearchParams();
14	    const setUser = useAuthStore((state) => state.setUser);
15	    const returnUrl = searchParams.get('returnUrl') || '/home';
16	    const {
17	        register,
18	        handleSubmit,
19	        formState: { errors },
20	    } = useForm({
21	        resolver: zodResolver(loginSchema),
22	        defaultValues: {
23	            username: '',
24	            password: '',
25	        },
26	    });
27	
28	    const mutation = useMutation({
29	        mutationFn: login,
30	        onSuccess: (data) => {
31	            setUser(data.user);
32	            navigate(returnUrl, { replace: true });
33	        },
34	    });
35	
36	    return (
37	        <section className='w-full max-w-sm rounded-2xl border border-slate-200 bg-white p-8 shadow-xl shadow-slate-200/60 dark:border-slate-800 dark:bg-slate-950 dark:shadow-none'>
38	            <header className='mb-6 space-y-2'>
39	                <div className='mb-4 flex h-10 w-10 items-center justify-center rounded-xl bg-gradient-to-br from-blue-600 to-blue-400 text-base font-bold text-white shadow-sm'>
40	                    T
41	                </div>
42	                <h1 className='text-2xl font-semibold text-slate-900 dark:text-slate-100'>TrmWordDict</h1>
43	                <p className='text-sm text-slate-500 dark:text-slate-400'>행정 용어 사전 시스템</p>
44	            </header>
45	            <form className='space-y-4' onSubmit={handleSubmit((values) => mutation.mutate(values))}>
46	                <div className='space-y-2'>
47	                    <label className='text-sm font-medium text-slate-700 dark:text-slate-300' htmlFor='username'>
48	                        아이디
49	                    </label>
50	                    <Input id='username' autoComplete='username' {...register('username')} />
51	                    {errors.username ? (
52	                        <p className='text-sm text-rose-600 dark:text-rose-400'>{errors.username.message}</p>
53	                    ) : null}
54	                </div>
55	                <div className='space-y-2'>
56	                    <label className='text-sm font-medium text-slate-700 dark:text-slate-300' htmlFor='password'>
57	                        비밀번호
58	                    </label>
59	                    <Input id='password' type='password' autoComplete='current-password' {...register('password')} />
60	                    {errors.password ? (
61	                        <p className='text-sm text-rose-600 dark:text-rose-400'>{errors.password.message}</p>
62	                    ) : null}
63	                </div>
64	                {mutation.isError ? (
65	                    <p className='text-sm text-rose-600 dark:text-rose-400'>로그인에 실패했습니다.</p>
66	                ) : null}
67	                <Button className='w-full' type='submit' disabled={mutation.isPending}>
68	                    로그인
69	                </Button>
70	            </form>
71	        </section>
72	    );
73	};
