70	const buildPageItems = (currentPage, totalPages) => {
71	    if (totalPages <= 1) {
72	        return [];
73	    }
74	
75	    if (totalPages <= 7) {
76	        return Array.from({ length: totalPages }, (_, index) => ({ type: 'page', value: index + 1 }));
77	    }
78	
79	    const pages = new Set([1, totalPages, currentPage - 1, currentPage, currentPage + 1]);
80	    const ordered = [...pages]
81	        .filter((page) => page >= 1 && page <= totalPages)
82	        .sort((a, b) => a - b);
83	
84	    const items = [];
85	    let lastPage = 0;
86	
87	    ordered.forEach((page) => {
88	        if (page - lastPage > 1) {
89	            items.push({ type: 'ellipsis', key: `ellipsis-${lastPage}-${page}` });
90	        }
91	
92	        items.push({ type: 'page', value: page });
93	        lastPage = page;
94	    });
95	
96	    return items;
97	};
